async () => {
  const out={url:location.href}; const wait=ms=>new Promise(r=>setTimeout(r,ms));
  const ident=n=>{try{return (n.tagName||'')+'.'+((n.className&&n.className.toString)?n.className.toString().trim().slice(0,46):'');}catch(e){return 'na';}};
  let shifts=[];
  try{new PerformanceObserver(l=>{for(const e of l.getEntries()){if(!e.hadRecentInput){let s=[];if(e.sources)for(const x of e.sources){if(x.node){let r={};try{const b=x.node.getBoundingClientRect();r={h:Math.round(b.height),top:Math.round(b.top)};}catch(_){}s.push(Object.assign({n:ident(x.node)},r));}}shifts.push({t:Math.round(e.startTime),v:+e.value.toFixed(4),s});}}}).observe({type:'layout-shift',buffered:true});}catch(e){out.shiftErr=String(e);}
  await wait(700);
  out.shifts=shifts.sort((a,b)=>b.v-a.v).slice(0,8);
  out.clsTotal=+shifts.reduce((a,b)=>a+b.v,0).toFixed(4);
  try{const sels=['.announcement-bar','.utility-bar','[class*="announcement"]'];let ab=[];sels.forEach(s=>{document.querySelectorAll(s).forEach(el=>{ab.push({sel:s,cls:ident(el),h:el.offsetHeight});});});out.bars=ab.slice(0,6);}catch(e){}
  try{const h=document.querySelector('sticky-header,.header-wrapper,.section-header');out.header=h?{cls:ident(h),h:h.offsetHeight}:null;}catch(e){}
  try{const m=document.querySelector('#MainContent,main,.content-for-layout');let kids=[];if(m){[...m.children].slice(0,5).forEach(c=>{const im=c.querySelector('img');let id=null;if(im){id={attrW:im.getAttribute('width'),attrH:im.getAttribute('height'),loading:im.getAttribute('loading'),fp:im.getAttribute('fetchpriority'),ar:getComputedStyle(im).aspectRatio,nW:im.naturalWidth,cW:im.clientWidth,cH:im.clientHeight};}kids.push({cls:ident(c),h:c.offsetHeight,top:Math.round(c.getBoundingClientRect().top),img:id});});}out.mainKids=kids;}catch(e){out.mkErr=String(e);}
  try{out.fonts=document.fonts?document.fonts.status:null;}catch(e){}
  try{out.jsonld=[...document.querySelectorAll('script[type="application/ld+json"]')].map(s=>s.textContent.replace(/\s+/g,' ').trim().slice(0,3500));}catch(e){}
  return out;
}
